#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1010,M=1e6+10,INF=0x3f3f3f3f;int head[N],h2[N],des[M],nxt[M],cgt=1,n,a[N],dp[N],cap[M],s,t,dep[N],que[N],H,T,ans;
inline void ins(const int &u,const int &v,const int &c)
{
	nxt[++cgt]=head[u];des[head[u]=cgt]=v;cap[cgt]=c;
	nxt[++cgt]=head[v];des[head[v]=cgt]=u;cap[cgt]=0;
}
inline bool bfs()
{
	memset(dep,0,(t+3)<<2);dep[que[H=T=0]=s]=1;
	while(H<=T){int u=que[H++];grep(u,i)if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;} return dep[t];
}
inline int dfs(const int &u=s,int in=INF)
{
	if(u==t)return in;int out=0;
	for(int &i=h2[u];i;i=nxt[i])if(cap[i]&&dep[des[i]]==dep[u]+1)
	{
		int v=des[i],tmp=dfs(v,min(in,cap[i]));
		cap[i]-=tmp;cap[i^1]+=tmp;out+=tmp;if(!(in-=tmp))break;
	}
	return out?out:dep[u]=0;
}
inline int dinic(){int res=0;while(bfs())memcpy(h2,head,(t+3)<<2),res+=dfs();return res;}
int main()
{
//	FIN("data.in");//FOUT("mine.out");
	n=read();rep(1,n,i){a[i]=read();for(int j=1;j<i;++j)if(a[i]>=a[j])chkmax(dp[i],dp[j]);++dp[i];}
	if(n==1)return puts("1\n1\n1"),0;
	rep(1,n,i)chkmax(ans,dp[i]);printf("%d\n",ans);
	s=n*2+1;t=n*2+2;rep(1,n,i)
	{
		rep(i+1,n,j)if(a[j]>=a[i]&&dp[j]==dp[i]+1)ins(i+n,j,1);
		ins(i,i+n,1);if(dp[i]==1)ins(s,i,1);if(dp[i]==ans)ins(i+n,t,1);
	}
//	rep(1,n,u)grep(u,i)printf("%d %d %d\n",u,des[i],cap[i]);
	printf("%d\n",dinic());memset(head,0,(t+5)<<2);cgt=1;
	
	s=n*2+1;t=n*2+2;rep(1,n,i)
	{
		rep(i+1,n,j)if(a[j]>=a[i]&&dp[j]==dp[i]+1)ins(i+n,j,1);
		ins(i,i+n,i==n||i==1?INF:1);if(dp[i]==1)ins(s,i,i==1?INF:1);if(dp[i]==ans)ins(i+n,t,i==n?INF:1);
	}
	
	printf("%d\n",dinic());return 0;
}
